-- Query: OrderReportByDate
SELECT Orders.OrderDate, Customers.FirstName, Customers.LastName, OrderItems.Description, OrderDetails.OrderItemID, OrderDetails.Units, OrderDetails.LineTotal, Orders.OrderID, Customers.CustomerID, Schools.School, IIf(IsNull([TotalPayments]),0,[TotalPayments]) AS TotalOrderPayments, IIf(IsNull([TotalDeposits]),0,[TotalDeposits]) AS TotalOrderDeposits, IIf(IsNull([TotalPaymentsBD]),0,[TotalPaymentsBD]) AS TotalOrderPaymentsBD, IIf(IsNull([TotalDepositsBD]),0,[TotalDepositsBD]) AS TotalOrderDepositsBD
FROM (((((((Orders RIGHT JOIN OrderDetails ON Orders.OrderID = OrderDetails.OrderID) LEFT JOIN OrderItems ON OrderDetails.OrderItemID = OrderItems.OrderItemID) LEFT JOIN Customers ON Orders.CustomerID = Customers.CustomerID) LEFT JOIN Schools ON Customers.SchoolID = Schools.SchoolID) LEFT JOIN qOrderTotalPayments ON Orders.OrderID = qOrderTotalPayments.OrderID) LEFT JOIN qOrderTotalDeposits ON Orders.OrderID = qOrderTotalDeposits.OrderID) LEFT JOIN qOrderDateTotalPayments ON Orders.OrderDate = qOrderDateTotalPayments.OrderDate) LEFT JOIN qOrderDateTotalDeposits ON Orders.OrderDate = qOrderDateTotalDeposits.OrderDate
GROUP BY Orders.OrderDate, Customers.FirstName, Customers.LastName, OrderItems.Description, OrderDetails.OrderItemID, OrderDetails.Units, OrderDetails.LineTotal, Orders.OrderID, Customers.CustomerID, Schools.School, IIf(IsNull([TotalPayments]),0,[TotalPayments]), IIf(IsNull([TotalDeposits]),0,[TotalDeposits]), IIf(IsNull([TotalPaymentsBD]),0,[TotalPaymentsBD]), IIf(IsNull([TotalDepositsBD]),0,[TotalDepositsBD]);

